    10→import theme from '../../styles/theme';
    11→import { InvoiceCashbackProps } from './models';
    12→import { PropsRootStack } from '../../routes/Models';
    13→import InvoiceCashbackSummaryView from './view';
    14→
    15→const InvoiceCashbackSummary: FC<InvoiceCashbackProps> = ({ route }) => {
    16→  useScreenViewTracking({ route, title: 'Cashback na fatura' });
    17→  const navigation = useNavigation<NavigationProp<PropsRootStack>>();
    18→  const isFocused = useIsFocused();
    19→  const { height } = Dimensions.get('window');
    20→  const { hasRedeemed, markAsRedeemed } = usePermission();
    21→  const alreadyMarkedRef = useRef(false);
    22→  const [hasAttemptedRescue, setHasAttemptedRescue] = useState(false);
    23→
    24→  const { conversionFactor } = usePoints();
    25→  const {
    26→    isLoading: isRescueLoading,
    27→    isError: isRescueFailed,
    28→    responseStatus: rescueStatus,
    29→    rescueRequest,
    30→    reset: rescueClear,
    31→  } = useRescue();
    32→
    33→  useLayoutEffect(() => {
    34→    if (isFocused) {
    35→      setHasAttemptedRescue(false);
    36→      rescueClear();
    37→    }
    38→  }, [isFocused, rescueClear]);
    39→
    40→  useFocusEffect(
    41→    React.useCallback(() => {
    42→      setHasAttemptedRescue(false);
    43→      rescueClear();
    44→      return undefined;
    45→    }, [rescueClear])
    46→  );
    47→
    48→  const handleGoBack = () => {
    49→    setHasAttemptedRescue(false);
